Code Good:
trait StrExt {
    fn is_blank(&self) -> bool;
    fn truncate_to(&self, max: usize) -> &str;
}

impl StrExt for str {
    fn is_blank(&self) -> bool {
        self.trim().is_empty()
    }
    fn truncate_to(&self, max: usize) -> &str {
        if self.len() <= max { self }
        else {
            let mut end = max;
            while !self.is_char_boundary(end) { end -= 1; }
            &self[..end]
        }
    }
}

assert!("  ".is_blank());

