use std::ops::Deref;

struct SortedVec<T: Ord>(Vec<T>);

impl<T: Ord> Deref for SortedVec<T> {
    type Target = [T];
    fn deref(&self) -> &[T] { &self.0 }
}

impl<T: Ord> SortedVec<T> {
    fn insert(&mut self, val: T) {
        let pos = self.0.binary_search(&val).unwrap_or_else(|i| i);
        self.0.insert(pos, val);
    }
}

let sv = SortedVec(vec![1, 3, 5]);
assert_eq!(sv.len(), 3); // via Deref to [T]
assert!(sv.contains(&3));

